const express = require('express')
const cors = require('cors')
const helmet = require('helmet')
const morgan = require('morgan')
const cookieParser = require('cookie-parser')
const rateLimit = require('express-rate-limit')
require('dotenv').config()

const authRoutes = require('./routes/auth.routes')
const adminRoutes = require('./routes/admin.routes')
const tenantRoutes = require('./routes/tenant.routes')
const userRoutes = require('./routes/user.routes')
const studentRoutes = require('./routes/student.routes')
const classRoutes = require('./routes/class.routes')
const subjectRoutes = require('./routes/subject.routes')
const scoreRoutes = require('./routes/score.routes')
const scoreComponentRoutes = require('./routes/score-component.routes')
const promotionRoutes = require('./routes/promotion.routes')
const yearEndPromotionRoutes = require('./routes/year-end-promotion.routes')
const reportRoutes = require('./routes/report.routes')
const settingsRoutes = require('./routes/settings.routes')
const parentRoutes = require('./routes/parent.routes')
const exportRoutes = require('./routes/export.routes')
const monitoringRoutes = require('./routes/monitoring.routes')
const feeRoutes = require('./routes/fee.routes')
const academicYearRoutes = require('./routes/academic-year.routes')
const { errorHandler } = require('./middleware/errorHandler')

const app = express()

// Rate limit bypass for automated testing (Playwright)
const skipIfBypassToken = (req) => {
  if (process.env.NODE_ENV === 'test') return true
  const bypassSecret = process.env.RATE_LIMIT_BYPASS_SECRET
  return bypassSecret && req.headers['x-ratelimit-bypass'] === bypassSecret
}

// Global rate limiter: 500 req/min per IP
const globalLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 500,
  standardHeaders: true,
  legacyHeaders: false,
  skip: skipIfBypassToken,
  message: { error: { code: 'TOO_MANY_REQUESTS', message: 'Too many requests, please try again later' } }
})

// Middleware
app.use(globalLimiter)
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "blob:"],
      connectSrc: ["'self'", process.env.CORS_ORIGIN || 'http://localhost:3000'],
      fontSrc: ["'self'"]
    }
  }
}))
app.use(cors({
  origin: process.env.CORS_ORIGIN || 'http://localhost:3000',
  credentials: true
}))
app.use(morgan('dev'))
app.use(express.json({ limit: '1mb' }))
app.use(express.urlencoded({ extended: true }))
app.use(cookieParser())

// Health check
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() })
})

// Route-specific rate limiters
const exportLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 20,
  message: { error: { code: 'TOO_MANY_REQUESTS', message: 'Export rate limit exceeded' } }
})

const monitoringLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 4,
  message: { error: { code: 'TOO_MANY_REQUESTS', message: 'Monitoring rate limit exceeded' } }
})

// API Routes
app.use('/api/auth', authRoutes)
app.use('/api/admin', adminRoutes)
app.use('/api/tenants', tenantRoutes)
app.use('/api/users', userRoutes)
app.use('/api/students', studentRoutes)
app.use('/api/classes', classRoutes)
app.use('/api/subjects', subjectRoutes)
app.use('/api/scores', scoreRoutes)
app.use('/api/score-components', scoreComponentRoutes)
app.use('/api/promotion', promotionRoutes)
app.use('/api/promotion', yearEndPromotionRoutes)
app.use('/api/reports', reportRoutes)
app.use('/api/settings', settingsRoutes)
app.use('/api/parents', parentRoutes)
app.use('/api/export', exportLimiter, exportRoutes)
app.use('/api/monitoring', monitoringLimiter, monitoringRoutes)
app.use('/api/fees', feeRoutes)
app.use('/api/academic-years', academicYearRoutes)

// Error handling
app.use(errorHandler)

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Route not found' } })
})

const PORT = process.env.PORT || 5001

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`)
})

module.exports = app

const jwt = require('jsonwebtoken')
const { LRUCache } = require('lru-cache')
const prisma = require('../lib/prisma')
const { AppError } = require('./errorHandler')

const userCache = new LRUCache({ max: 500, ttl: 60 * 1000 })
const settingsCache = new LRUCache({ max: 100, ttl: 5 * 60 * 1000 })

const authenticate = async (req, res, next) => {
  try {
    const token = req.cookies.token || req.headers.authorization?.split(' ')[1]

    if (!token) {
      throw new AppError('Authentication required', 401, 'AUTH_REQUIRED')
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET)

    let user = userCache.get(decoded.sub)
    if (!user) {
      user = await prisma.user.findUnique({
        where: { id: decoded.sub },
        include: { tenant: true }
      })
      if (user) userCache.set(decoded.sub, user)
    }

    if (!user || !user.isActive) {
      throw new AppError('User not found or inactive', 401, 'USER_INACTIVE')
    }

    req.user = user
    req.tenantId = user.tenantId

    // Attach tenant settings for non-platform admins
    if (user.tenantId) {
      let settings = settingsCache.get(user.tenantId)
      if (!settings) {
        settings = await prisma.tenantSettings.findUnique({ where: { tenantId: user.tenantId } })
        if (settings) settingsCache.set(user.tenantId, settings)
      }
      req.tenantSettings = settings
    }

    next()
  } catch (error) {
    if (error.name === 'JsonWebTokenError' || error.name === 'TokenExpiredError') {
      return next(new AppError('Invalid or expired token', 401, 'INVALID_TOKEN'))
    }
    next(error)
  }
}

// Invalidate user cache on user update/delete
const invalidateUserCache = (userId) => userCache.delete(userId)
const invalidateSettingsCache = (tenantId) => settingsCache.delete(tenantId)

const authorize = (...roles) => {
  return (req, res, next) => {
    if (!roles.includes(req.user.role)) {
      return next(new AppError('Insufficient permissions', 403, 'FORBIDDEN'))
    }
    next()
  }
}

// Tenant isolation: PLATFORM_ADMIN is not constrained by tenantId
const tenantGuard = (req, res, next) => {
  if (req.user.role === 'PLATFORM_ADMIN') {
    return next()
  }
  if (!req.tenantId) {
    return next(new AppError('Tenant context required', 403, 'NO_TENANT'))
  }
  next()
}

module.exports = { authenticate, authorize, tenantGuard, invalidateUserCache, invalidateSettingsCache }

import axios, { AxiosError, InternalAxiosRequestConfig } from 'axios'
import { useAuthStore } from '@/store/auth'

const API_URL = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5001/api'

export const api = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  headers: { 'Content-Type': 'application/json' },
})

api.interceptors.request.use(
  (config: InternalAxiosRequestConfig) => {
    const token = useAuthStore.getState().token
    if (token) config.headers.Authorization = `Bearer ${token}`
    return config
  },
  (error) => Promise.reject(error)
)

api.interceptors.response.use(
  (response) => response,
  async (error: AxiosError<{ error?: { message?: string; code?: string } }>) => {
    // Handle blob error responses
    if (error.config?.responseType === 'blob' && error.response?.data instanceof Blob) {
      try {
        const text = await (error.response.data as Blob).text()
        error.response.data = JSON.parse(text)
      } catch {}
    }
    if (error.response?.status === 401) {
      useAuthStore.getState().logout()
      if (typeof window !== 'undefined') window.location.href = '/login'
    }
    return Promise.reject(error)
  }
)

