.stagger-6 { transition-delay: 400ms !important; }
.stagger-7 { transition-delay: 480ms !important; }
.stagger-8 { transition-delay: 560ms !important; }

/* Wave divider SVG containers */
.wave-divider {
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  overflow: hidden;
  line-height: 0;
}
.wave-divider svg {
  display: block;
  width: 100%;
  height: 60px;
}

/* Floating particles */
.particle {
  position: absolute;
  width: 4px;
  height: 4px;
  background: rgba(96, 165, 250, 0.3);
  border-radius: 50%;
  pointer-events: none;
}
