            </div>
          </div>
        </div>
        {/* Mobile menu */}
        <div className={`md:hidden overflow-hidden transition-all duration-300 ${mobileMenuOpen ? 'max-h-64 border-t border-white/10' : 'max-h-0'}`}>
          <div className="bg-gray-950/95 backdrop-blur-md px-4 py-4 space-y-2">
