name: API & Performance Tests

on:
  workflow_dispatch:
    inputs:
      test_type:
        description: 'Test type to run'
        required: true
        default: 'all'
        type: choice
        options:
          - all
          - api-tests
          - performance
  workflow_run:
    workflows: ['Deploy to VPS']
    types: [completed]

env:
  NODE_VERSION: '20'

jobs:
  test:
    runs-on: ubuntu-latest
    timeout-minutes: 15
    # Skip if triggered by a failed deploy
    if: ${{ github.event_name != 'workflow_run' || github.event.workflow_run.conclusion == 'success' }}

    steps:
      - name: Checkout repository
        uses: actions/checkout@v4

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: ${{ env.NODE_VERSION }}

      - name: Install test dependencies
        working-directory: tests
        run: npm ci

      - name: Install Playwright
        working-directory: tests
        run: npx playwright install --with-deps

      # ── Run tests ──
      - name: Run API tests
        working-directory: tests
        if: ${{ github.event.inputs.test_type == 'all' || github.event.inputs.test_type == 'api-tests' || github.event_name == 'workflow_run' }}
        run: npx playwright test --project=api-tests
        env:
          API_BASE_URL: ${{ secrets.API_BASE_URL }}
          TENANT_CODE: ${{ secrets.TENANT_CODE }}
          SUPER_ADMIN_EMAIL: ${{ secrets.SUPER_ADMIN_EMAIL }}
          SUPER_ADMIN_PASSWORD: ${{ secrets.SUPER_ADMIN_PASSWORD }}
          STAFF_EMAIL: ${{ secrets.STAFF_EMAIL }}
          STAFF_PASSWORD: ${{ secrets.STAFF_PASSWORD }}
          TEACHER_EMAIL: ${{ secrets.TEACHER_EMAIL }}
          TEACHER_PASSWORD: ${{ secrets.TEACHER_PASSWORD }}
          PARENT_EMAIL: ${{ secrets.PARENT_EMAIL }}
          PARENT_PASSWORD: ${{ secrets.PARENT_PASSWORD }}
          PLATFORM_ADMIN_EMAIL: ${{ secrets.PLATFORM_ADMIN_EMAIL }}
          PLATFORM_ADMIN_PASSWORD: ${{ secrets.PLATFORM_ADMIN_PASSWORD }}
          RATE_LIMIT_BYPASS_SECRET: ${{ secrets.RATE_LIMIT_BYPASS_SECRET }}

      - name: Run performance tests
        working-directory: tests
        if: ${{ github.event.inputs.test_type == 'all' || github.event.inputs.test_type == 'performance' || github.event_name == 'workflow_run' }}
        run: npx playwright test --project=performance
        env:
          API_BASE_URL: ${{ secrets.API_BASE_URL }}
          TENANT_CODE: ${{ secrets.TENANT_CODE }}
          SUPER_ADMIN_EMAIL: ${{ secrets.SUPER_ADMIN_EMAIL }}
          SUPER_ADMIN_PASSWORD: ${{ secrets.SUPER_ADMIN_PASSWORD }}
          STAFF_EMAIL: ${{ secrets.STAFF_EMAIL }}
          STAFF_PASSWORD: ${{ secrets.STAFF_PASSWORD }}
          TEACHER_EMAIL: ${{ secrets.TEACHER_EMAIL }}
          TEACHER_PASSWORD: ${{ secrets.TEACHER_PASSWORD }}
          PARENT_EMAIL: ${{ secrets.PARENT_EMAIL }}
          PARENT_PASSWORD: ${{ secrets.PARENT_PASSWORD }}
          PLATFORM_ADMIN_EMAIL: ${{ secrets.PLATFORM_ADMIN_EMAIL }}
          PLATFORM_ADMIN_PASSWORD: ${{ secrets.PLATFORM_ADMIN_PASSWORD }}
          RATE_LIMIT_BYPASS_SECRET: ${{ secrets.RATE_LIMIT_BYPASS_SECRET }}

      # ── Reports ──
      - name: Upload test report
        uses: actions/upload-artifact@v4
        if: always()
        with:
          name: playwright-report
          path: tests/playwright-report/
          retention-days: 14

      - name: Upload test results
        uses: actions/upload-artifact@v4
        if: always()
        with:
          name: test-results
          path: tests/test-results/
          retention-days: 7

