function useInView(offset = 100, ready = true) {
  const ref = useRef<HTMLDivElement>(null)
  const [isVisible, setIsVisible] = useState(false)

  useEffect(() => {
    if (!ready) return
    const el = ref.current
    if (!el) return
    let triggered = false
    const check = () => {
      if (triggered) return
      if (el.getBoundingClientRect().top < window.innerHeight - offset) {
        triggered = true
        setIsVisible(true)
      }
    }
    check()
    window.addEventListener('scroll', check, { passive: true })
    return () => window.removeEventListener('scroll', check)
  }, [ready, offset])

  return { ref, isVisible }
}

function useScrollReveal(options = { threshold: 0.1, rootMargin: '0px 0px -50px 0px' }) {
  const ref = useRef<HTMLDivElement>(null)
  const [isVisible, setIsVisible] = useState(false)

  useEffect(() => {
    const el = ref.current
    if (!el) return
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        setIsVisible(true)
        observer.unobserve(el)
      }
    }, options)
    observer.observe(el)
    return () => observer.disconnect()
  }, [])

  return { ref, isVisible }
}

// ==================== COMPONENTS ====================

function AnimatedCounter({ target }: { target: string }) {
  const ref = useRef<HTMLSpanElement>(null)
  const [display, setDisplay] = useState('0')
  const [started, setStarted] = useState(false)

  useEffect(() => {
    const el = ref.current
    if (!el) return
    const check = () => {
      if (started) return
      if (el.getBoundingClientRect().top < window.innerHeight - 50) setStarted(true)
    }
    check()
    window.addEventListener('scroll', check, { passive: true })
    return () => window.removeEventListener('scroll', check)
  }, [started])

  useEffect(() => {
    if (!started) return
    const num = parseInt(target.replace(/[^0-9]/g, ''))
    if (isNaN(num)) { setDisplay(target); return }
    const suffix = target.replace(/[0-9]/g, '')
    const steps = 40
    let step = 0
    const timer = setInterval(() => {
      step++
      const current = Math.min(Math.round((num / steps) * step), num)
      setDisplay(current.toLocaleString('vi-VN') + suffix)
      if (step >= steps) clearInterval(timer)
    }, 1500 / steps)
    return () => clearInterval(timer)
  }, [started, target])

  return <span ref={ref}>{display}</span>
}

